# Category: business_logic_flaw

def validate_cart_items(cart_items):
    for item in cart_items:
        if item['quantity'] <= 0 or item['price'] < 0:
            return False, "Invalid cart items"
    return True, cart_items

def apply_discount_codes(cart_items, discount_code, user):
    discount_codes = {
        'SUMMER10': {'discount': 0.10, 'user_tier': 'all'},
        'ADMIN50': {'discount': 0.50, 'user_tier': 'admin'},
        'VIP20': {'discount': 0.20, 'user_tier': 'vip'}
    }
    if discount_code in discount_codes:
        code_info = discount_codes[discount_code]
        if user['tier'] == code_info['user_tier'] or code_info['user_tier'] == 'all':
            total = sum(item['price'] * item['quantity'] for item in cart_items)
            discount = total * code_info['discount']
            return True, total - discount
        else:
            return False, "User not eligible for this discount code"
    return False, "Invalid discount code"

def calculate_tax(total, tax_rate=0.07):
    tax = total * tax_rate
    return total + tax

def process_payment(total, payment_info):
    if payment_info['valid']:
        return True, "Payment processed successfully"
    return False, "Payment failed"

def create_order_record(cart_items, total, user):
    order_record = {
        'user_id': user['id'],
        'items': cart_items,
        'total': total,
        'status': 'completed'
    }
    return order_record

def checkout_process(cart_items, discount_code, user, payment_info):
    valid, result = validate_cart_items(cart_items)
    if not valid:
        return result
    
    valid, result = apply_discount_codes(cart_items, discount_code, user)
    if not valid:
        return result
    
    total_with_tax = calculate_tax(result)
    
    valid, result = process_payment(total_with_tax, payment_info)
    if not valid:
        return result
    
    order_record = create_order_record(cart_items, total_with_tax, user)
    return order_record

# Example usage
